import React, { useState } from 'react';
import axios from 'axios';
import { ClipboardPaste, Save, Trash2, Loader2, Info } from 'lucide-react';

const GestionInventario = ({ localId, onComplete }) => {
    const [rawText, setRawText] = useState('');
    const [preview, setPreview] = useState([]);
    const [loading, setLoading] = useState(false);

    const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

    // Esta función procesa el texto pegado de Excel (que usa Tabulaciones como separador)
    const procesarPegado = (text) => {
        setRawText(text);
        const filas = text.split('\n').filter(linea => linea.trim() !== '');
        
        const productosProcesados = filas.map(linea => {
            const columnas = linea.split('\t'); // Excel usa tabs
            return {
                tipo: columnas[0] || '',
                marca: columnas[1] || '',
                contenido: columnas[2] || '',
                categoria: columnas[3] || 'Almacén',
                precioNuevo: columnas[4] || '',
                precioViejo: columnas[5] || '',
                stock: columnas[6] || ''
            };
        });
        setPreview(productosProcesados);
    };

    const handleGuardarTodo = async () => {
        if (preview.length === 0) return alert("No hay datos para cargar.");

        setLoading(true);
        try {
            const payload = {
                localId,
                productos: preview.map(p => ({
                    ...p,
                    producto: `${p.tipo} ${p.marca} ${p.contenido}`.trim(),
                    precioNuevo: Number(p.precioNuevo),
                    precioViejo: Number(p.precioViejo) || Number(p.precioNuevo),
                    stock: Number(p.stock) || 0
                }))
            };
            await axios.post(`${API_URL}/api/ofertas/bulk`, payload);
            alert(`¡Éxito! Se cargaron ${preview.length} productos.`);
            setRawText('');
            setPreview([]);
            onComplete();
        } catch (error) {
            alert("Error al guardar: " + error.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={container}>
            <div style={header}>
                <ClipboardPaste size={20} color="#107c41" />
                <h3 style={{margin:0}}>Carga Rápida desde Excel</h3>
            </div>

            <div style={instructions}>
                <Info size={14} />
                <span>Copia las columnas en Excel y pégalas aquí abajo. El orden debe ser: 
                <strong> Tipo > Marca > Contenido > Categoría > Precio Oferta > Precio Viejo > Stock</strong></span>
            </div>

            <textarea
                style={textAreaStyle}
                placeholder="Pega aquí los datos de tu Excel..."
                value={rawText}
                onChange={(e) => procesarPegado(e.target.value)}
            />

            {preview.length > 0 && (
                <div style={previewSection}>
                    <h4>Vista previa ({preview.length} filas)</h4>
                    <div style={tableWrapper}>
                        <table style={table}>
                            <thead>
                                <tr style={headerRow}>
                                    <th>Tipo</th><th>Marca</th><th>Contenido</th><th>Cat.</th><th>$ Oferta</th><th>Stock</th>
                                </tr>
                            </thead>
                            <tbody>
                                {preview.map((p, i) => (
                                    <tr key={i} style={rowStyle}>
                                        <td>{p.tipo}</td><td>{p.marca}</td><td>{p.contenido}</td>
                                        <td>{p.categoria}</td><td>${p.precioNuevo}</td><td>{p.stock}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                    <div style={footer}>
                        <button onClick={() => {setRawText(''); setPreview([]);}} style={btnCancel}>
                            <Trash2 size={16}/> Limpiar
                        </button>
                        <button onClick={handleGuardarTodo} style={btnSave} disabled={loading}>
                            {loading ? <Loader2 className="animate-spin" size={18}/> : <Save size={18}/>}
                            Confirmar y Cargar al Inventario
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

// --- ESTILOS ---
const container = { background: '#fff', borderRadius: '12px', border: '1px solid #e2e8f0', marginBottom: '30px', padding: '20px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)' };
const header = { display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '15px' };
const instructions = { background: '#f0f9ff', padding: '10px', borderRadius: '8px', fontSize: '0.85rem', color: '#0369a1', marginBottom: '15px', display: 'flex', gap: '10px', alignItems: 'center' };
const textAreaStyle = { width: '100%', height: '120px', padding: '15px', borderRadius: '8px', border: '2px dashed #cbd5e1', outline: 'none', fontFamily: 'monospace', fontSize: '0.9rem', resize: 'vertical' };
const previewSection = { marginTop: '20px', borderTop: '1px solid #f1f5f9', paddingTop: '15px' };
const tableWrapper = { maxHeight: '300px', overflowY: 'auto', border: '1px solid #f1f5f9', borderRadius: '8px' };
const table = { width: '100%', borderCollapse: 'collapse', fontSize: '0.85rem' };
const headerRow = { background: '#f8fafc', textAlign: 'left', borderBottom: '2px solid #e2e8f0' };
const rowStyle = { borderBottom: '1px solid #f1f5f9' };
const footer = { display: 'flex', justifyContent: 'space-between', marginTop: '15px' };
const btnSave = { background: '#107c41', color: 'white', border: 'none', padding: '10px 25px', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', display: 'flex', alignItems: 'center', gap: '8px' };
const btnCancel = { background: '#f1f5f9', border: 'none', padding: '10px 15px', borderRadius: '8px', cursor: 'pointer', color: '#64748b', display: 'flex', alignItems: 'center', gap: '8px' };

export default GestionInventario;
